  6→// ── Arg parsing helpers ──────────────────────────────────────────────
  7→const argv = process.argv.slice(2);
  8→
  9→function flag(name) {
 10→  const i = argv.indexOf(`--${name}`);
 11→  if (i === -1) return undefined;
 12→  const val = argv[i + 1];
 13→  return val && !val.startsWith("--") ? val : true;
 14→}
 15→
 16→function hasFlag(name) {
 17→  return argv.includes(`--${name}`);
 18→}
 19→
 20→function jsonFlag(name) {
 21→  const v = flag(name);
 22→  if (v === undefined || v === true) return undefined;
 23→  try { return JSON.parse(v); } catch { errExit(`Invalid JSON for --${name}`, "NOTION_VALIDATION", `Ensure --${name} is valid JSON`); }
 24→}
 25→
 26→// ── Output helpers ───────────────────────────────────────────────────
 27→function ok(data) { process.stdout.write(JSON.stringify(data, null, 2) + "\n"); process.exit(0); }
 28→function errExit(error, code, hint) {
 29→  process.stderr.write(JSON.stringify({ error, code, hint }) + "\n");
 30→  process.exit(1);
 31→}
