 90→// ── Retry with backoff (for 429) ─────────────────────────────────────
 91→async function withRetry(fn, retries = 3) {
 92→  for (let i = 0; i <= retries; i++) {
 93→    try { return await fn(); } catch (e) {
 94→      if (e.status === 429 && i < retries) {
 95→        const wait = e.body?.retry_after ? e.body.retry_after * 1000 : 1000 * Math.pow(2, i);
 96→        await new Promise(r => setTimeout(r, wait));
 97→        continue;
 98→      }
 99→      throw e;
100→    }
101→  }
102→}
103→
104→// ── Auto-pagination ──────────────────────────────────────────────────
105→async function paginate(fn) {
106→  let cursor = undefined;
107→  const all = [];
108→  do {
109→    const res = await fn(cursor);
110→    all.push(...res.results);
111→    cursor = res.has_more ? res.next_cursor : undefined;
112→  } while (cursor);
113→  return all;
114→}
115→
116→// ── Error wrapper ────────────────────────────────────────────────────
117→async function run(fn) {
118→  try { await fn(); } catch (e) {
119→    if (e.status === 401) errExit(e.message || "Unauthorized", "NOTION_AUTH_FAILED", "Check NOTION_API_KEY");
120→    if (e.status === 404) errExit(e.message || "Not found", "NOTION_NOT_FOUND", "Check sharing permissions");
121→    if (e.status === 429) errExit(e.message || "Rate limited", "NOTION_RATE_LIMIT", "Too many requests — try again later");
122→    if (e.code === "ECONNABORTED" || e.code === "ETIMEDOUT" || e.name === "AbortError")
123→      errExit("Request timed out", "NOTION_TIMEOUT", "Network issue — try again");
124→    if (e.status === 400) errExit(e.message || "Validation error", "NOTION_VALIDATION", JSON.stringify(e.body) || "Check parameters");
125→    errExit(e.message || String(e), "NOTION_ERROR", "Unexpected error");
126→  }
127→}
