129→// ── Sanitize properties for creation (strip status options/groups) ────
130→function sanitizePropsForCreate(properties) {
131→  const cleaned = {};
132→  for (const [name, config] of Object.entries(properties)) {
133→    if (config.status) {
134→      // Notion API rejects status.options and status.groups on creation
135→      cleaned[name] = { status: {} };
136→    } else {
137→      cleaned[name] = config;
138→    }
139→  }
140→  return cleaned;
141→}
