108→function install(targetDir, templateDir, packageVersion) {
109→  const founderOsDir = path.join(targetDir, '.founderOS');
110→  const claudeDir = path.join(targetDir, '.claude');
111→  const mf = manifest.createEmptyManifest(packageVersion);
112→
113→  // 1. Copy .founderOS/ template (clean slate — remove if corrupted/partial)
114→  if (fs.existsSync(founderOsDir)) {
115→    fs.rmSync(founderOsDir, { recursive: true });
116→  }
117→  const founderOsTemplate = path.join(templateDir, '.founderOS');
118→  if (fs.existsSync(founderOsTemplate)) {
119→    fs.cpSync(founderOsTemplate, founderOsDir, { recursive: true });
120→  } else {
121→    fs.mkdirSync(founderOsDir, { recursive: true });
122→  }
123→  output.success('Created .founderOS/');
124→
125→  // Ensure empty dirs exist
126→  for (const sub of ['config', 'context', 'auth', 'db']) {
127→    fs.mkdirSync(path.join(founderOsDir, sub), { recursive: true });
128→  }
129→
130→  // 2. Create .claude/ if needed
131→  fs.mkdirSync(claudeDir, { recursive: true });
132→
133→  // 3. Copy .claude/ template files (except CLAUDE.md and settings.json — handled separately)
134→  const claudeTemplate = path.join(templateDir, '.claude');
135→  const templateFiles = collectFiles(claudeTemplate, claudeTemplate);
136→  const specialFiles = ['CLAUDE.md', 'settings.json'];
137→
138→  let commandDirs = new Set();
139→  let skillDirs = new Set();
140→  let agentDirs = new Set();
141→
142→  for (const relFile of templateFiles) {
143→    if (specialFiles.includes(relFile)) continue;
144→
145→    const srcPath = path.join(claudeTemplate, relFile);
146→    const destPath = path.join(claudeDir, relFile);
147→    const manifestKey = path.join('.claude', relFile);
148→
149→    // Track namespace counts
150→    const parts = relFile.split(path.sep);
151→    if (parts[0] === 'commands' && parts.length > 1) commandDirs.add(parts[1]);
152→    if (parts[0] === 'skills' && parts.length > 1) skillDirs.add(parts[1]);
153→    if (parts[0] === 'agents' && parts.length > 1) agentDirs.add(parts[1]);
154→
155→    // Ensure parent dir
156→    fs.mkdirSync(path.dirname(destPath), { recursive: true });
157→
158→    if (fs.existsSync(destPath)) {
159→      // Pre-existing file — back it up
160→      const backupPath = destPath + '.pre-founderos.bak';
161→      fs.copyFileSync(destPath, backupPath);
162→      fs.copyFileSync(srcPath, destPath);
163→      const checksum = manifest.computeChecksum(destPath);
164→      manifest.addFileToManifest(mf, manifestKey, checksum, 'replaced-existing', {
165→        backup: manifestKey + '.pre-founderos.bak',
166→      });
167→    } else {
168→      fs.copyFileSync(srcPath, destPath);
169→      const checksum = manifest.computeChecksum(destPath);
170→      manifest.addFileToManifest(mf, manifestKey, checksum, 'managed');
171→    }
172→  }
173→
174→  output.success(`Created .claude/commands/ (${commandDirs.size} namespaces)`);
175→  output.success(`Created .claude/skills/ (${skillDirs.size} domains)`);
176→  output.success(`Created .claude/agents/ (${agentDirs.size} teams)`);
177→
178→  // 4. Handle CLAUDE.md (project root, not .claude/)
179→  const claudeMdPath = path.join(targetDir, 'CLAUDE.md');
180→  claudeMd.mergeClaudeMd(claudeMdPath, templateDir);
181→  output.success('Generated CLAUDE.md');
182→
183→  // 5. Handle settings.json
184→  const settingsPath = path.join(claudeDir, 'settings.json');
185→  settingsJson.mergeSettingsJson(settingsPath);
186→  output.success('Generated .claude/settings.json');
187→
188→  // 6. Create .env, .env.example, .gitignore (skip if they already exist)
189→  createEnvFiles(targetDir);
190→
191→  // 7. Write version and manifest
192→  manifest.writeVersion(targetDir, packageVersion);
193→  manifest.writeManifest(targetDir, mf);
194→
195→  return { commandDirs: commandDirs.size, skillDirs: skillDirs.size, agentDirs: agentDirs.size };
196→}
197→
198→module.exports = { install, collectFiles };
