 23→  const warnings = [];
 24→  let updatedCount = 0;
 25→  let addedCount = 0;
 26→  let removedCount = 0;
 27→
 28→  // 1. Update .founderOS/infrastructure/ wholesale
 29→  if (fs.existsSync(founderOsTemplate)) {
 30→    // Remove old infrastructure, copy new
 31→    const infraDest = path.join(founderOsDir, 'infrastructure');
 32→    if (fs.existsSync(infraDest)) {
 33→      fs.rmSync(infraDest, { recursive: true });
 34→    }
 35→    const infraSrc = path.join(founderOsTemplate, 'infrastructure');
 36→    if (fs.existsSync(infraSrc)) {
 37→      fs.cpSync(infraSrc, infraDest, { recursive: true });
 38→    }
 39→    // Copy scripts
 40→    const scriptsSrc = path.join(founderOsTemplate, 'scripts');
 41→    const scriptsDest = path.join(founderOsDir, 'scripts');
 42→    if (fs.existsSync(scriptsSrc)) {
 43→      if (fs.existsSync(scriptsDest)) fs.rmSync(scriptsDest, { recursive: true });
 44→      fs.cpSync(scriptsSrc, scriptsDest, { recursive: true });
 45→    }
 46→  }
 47→  output.success('Refreshed .founderOS/ infrastructure');
 48→
 49→  // 2. Process .claude/ files
 50→  const templateFiles = collectFiles(claudeTemplate, claudeTemplate);
 51→  const specialFiles = ['CLAUDE.md', 'settings.json'];
 52→  const templateSet = new Set(templateFiles.filter((f) => !specialFiles.includes(f)));
 53→
 54→  // 2a. Files in old manifest — check for changes
