 60→    if (!fs.existsSync(destPath)) {
 61→      // User deleted this file
 62→      mf.addFileToManifest(newManifest, relKey, null, 'user-removed');
 63→      continue;
 64→    }
 65→
 66→    if (templateSet.has(fileRelToTemplate)) {
 67→      // File exists in both old and new versions
 68→      const currentChecksum = mf.computeChecksum(destPath);
 69→      const isModified = currentChecksum !== entry.checksum;
 70→
 71→      if (isModified && !force) {
 72→        // User modified — skip
 73→        mf.addFileToManifest(newManifest, relKey, currentChecksum, 'user-modified');
 74→        warnings.push(relKey);
 75→      } else {
 76→        // Unmodified (or --force) — overwrite
 77→        if (isModified && force) {
 78→          // Backup before overwriting
 79→          fs.copyFileSync(destPath, destPath + '.bak');
 80→        }
 81→        const srcPath = path.join(claudeTemplate, fileRelToTemplate);
 82→        fs.copyFileSync(srcPath, destPath);
 83→        const newChecksum = mf.computeChecksum(destPath);
 84→        // Carry forward replaced-existing status and backup path
 85→        if (entry.status === 'replaced-existing' && entry.backup) {
 86→          mf.addFileToManifest(newManifest, relKey, newChecksum, 'replaced-existing', {
 87→            backup: entry.backup,
 88→          });
 89→        } else {
 90→          mf.addFileToManifest(newManifest, relKey, newChecksum, 'managed');
 91→        }
 92→        updatedCount++;
 93→      }
 94→      templateSet.delete(fileRelToTemplate);
 95→    } else {
 96→      // File in old manifest but not in new version — removed upstream
 97→      const currentChecksum = mf.computeChecksum(destPath);
 98→      if (currentChecksum === entry.checksum) {
 99→        // Unmodified — safe to delete
100→        fs.unlinkSync(destPath);
101→        removedCount++;
102→      } else {
103→        // User modified — keep it, remove from manifest
104→        // (becomes the user's file)
105→      }
106→    }
107→  }
108→
109→  // 2b. New files (in template but not in old manifest)
110→  for (const relFile of templateSet) {
111→    const destPath = path.join(claudeDir, relFile);
112→    const srcPath = path.join(claudeTemplate, relFile);
113→    const manifestKey = path.join('.claude', relFile);
114→
115→    fs.mkdirSync(path.dirname(destPath), { recursive: true });
116→
117→    if (fs.existsSync(destPath)) {
118→      // Pre-existing user file at this new path
119→      const backupPath = destPath + '.pre-founderos.bak';
120→      fs.copyFileSync(destPath, backupPath);
121→      fs.copyFileSync(srcPath, destPath);
122→      const checksum = mf.computeChecksum(destPath);
123→      mf.addFileToManifest(newManifest, manifestKey, checksum, 'replaced-existing', {
124→        backup: manifestKey + '.pre-founderos.bak',
125→      });
126→    } else {
127→      fs.copyFileSync(srcPath, destPath);
128→      const checksum = mf.computeChecksum(destPath);
129→      mf.addFileToManifest(newManifest, manifestKey, checksum, 'managed');
130→    }
131→    addedCount++;
132→  }
133→
134→  // 3. CLAUDE.md (project root) and settings.json
135→  const claudeMdPath = path.join(targetDir, 'CLAUDE.md');
136→  claudeMd.mergeClaudeMd(claudeMdPath, templateDir);
137→
138→  const settingsPath = path.join(claudeDir, 'settings.json');
139→  settingsJson.mergeSettingsJson(settingsPath);
