141→  // 4. Write updated version and manifest
142→  mf.writeVersion(targetDir, packageVersion);
143→  mf.writeManifest(targetDir, newManifest);
144→
145→  // 5. Output summary
146→  if (updatedCount > 0) output.success(`Updated ${updatedCount} files`);
147→  if (addedCount > 0) output.success(`Added ${addedCount} new files`);
148→  if (removedCount > 0) output.success(`Removed ${removedCount} obsolete files`);
149→  if (warnings.length > 0) {
150→    output.warn(`Skipped ${warnings.length} files (modified by you):`);
151→    for (const w of warnings) output.info(`  ${w}`);
