  1→// lib/uninstaller.js
  2→// Remove founderOS files, restore backups, clean markers from CLAUDE.md
  3→'use strict';
  4→
  5→const fs = require('fs');
  6→const path = require('path');
  7→const mf = require('./manifest.js');
  8→const claudeMd = require('./claude-md.js');
  9→const settingsJson = require('./settings-json.js');
 10→const output = require('./output.js');
 11→
 12→function uninstall(targetDir, force) {
 13→  const manifest = mf.readManifest(targetDir);
 14→  if (!manifest) {
 15→    output.error('No Founder OS installation found in this directory.');
 16→    return false;
 17→  }
 18→
 19→  let removedCount = 0;
 20→  let skippedCount = 0;
 21→  let restoredCount = 0;
 22→  const skipped = [];
 23→
 24→  for (const [relKey, entry] of Object.entries(manifest.files)) {
 25→    const destPath = path.join(targetDir, relKey);
 26→    if (!fs.existsSync(destPath)) continue;
 27→
 28→    // Recompute checksum to detect modifications made after install/update
 29→    const isModified =
 30→      entry.checksum && mf.computeChecksum(destPath) !== entry.checksum;
 31→    const effectiveStatus = isModified ? 'user-modified' : entry.status;
 32→
 33→    if (effectiveStatus === 'user-modified' && !force) {
 34→      skipped.push(relKey);
 35→      skippedCount++;
 36→      continue;
 37→    }
 38→
 39→    // Check if we need to restore a backup
 40→    if (entry.status === 'replaced-existing' && entry.backup) {
 41→      const backupPath = path.join(targetDir, entry.backup);
 42→      if (fs.existsSync(backupPath)) {
 43→        fs.copyFileSync(backupPath, destPath);
 44→        fs.unlinkSync(backupPath);
 45→        restoredCount++;
 46→        continue;
 47→      }
 48→    }
 49→
 50→    // If --force and modified, backup before removing
 51→    if (force && isModified) {
 52→      fs.copyFileSync(destPath, destPath + '.bak');
 53→    }
 54→
 55→    fs.unlinkSync(destPath);
 56→    removedCount++;
 57→  }
 58→
 59→  // Remove founderOS section from CLAUDE.md (project root)
 60→  const claudeMdPath = path.join(targetDir, 'CLAUDE.md');
 61→  claudeMd.removeFromClaudeMd(claudeMdPath);
 62→
 63→  // Remove founderOS entries from settings.json
 64→  const settingsPath = path.join(targetDir, '.claude', 'settings.json');
 65→  settingsJson.removeFromSettingsJson(settingsPath);
 66→
 67→  // Note: plugins installed via --with-plugins are NOT removed here.
 68→  // They are managed by the `claude` CLI. The plugins manifest state is
 69→  // deleted with .founderOS/ below.
 70→
 71→  // Remove .founderOS/ directory
 72→  const founderOsDir = path.join(targetDir, '.founderOS');
 73→  if (fs.existsSync(founderOsDir)) {
 74→    fs.rmSync(founderOsDir, { recursive: true });
 75→  }
 76→
 77→  // Clean up empty directories in .claude/
 78→  cleanEmptyDirs(path.join(targetDir, '.claude'));
 79→
 80→  output.success(`Removed ${removedCount} files`);
 81→  if (restoredCount > 0) output.success(`Restored ${restoredCount} original files from backup`);
 82→  if (skippedCount > 0) {
 83→    output.warn(`Skipped ${skippedCount} modified files (use --force to remove):`);
 84→    for (const s of skipped) output.info(`  ${s}`);
 85→  }
 86→
 87→  return true;
 88→}
 89→
 90→function cleanEmptyDirs(dir) {
 91→  if (!fs.existsSync(dir)) return;
 92→  const entries = fs.readdirSync(dir, { withFileTypes: true });
 93→  for (const entry of entries) {
 94→    if (entry.isDirectory()) {
 95→      cleanEmptyDirs(path.join(dir, entry.name));
 96→    }
 97→  }
 98→  // Re-check after cleaning children
 99→  if (fs.readdirSync(dir).length === 0) {
100→    fs.rmdirSync(dir);
101→  }
102→}
103→
104→module.exports = { uninstall };
