 279→```javascript
 280→// lib/memory-init.mjs — Lazy initialization for Memory Engine DB
 281→import path from 'node:path';
 282→import fs from 'node:fs';
 283→import { openDb, runSqlFile, tableCount, closeDb } from './db-helper.mjs';
 284→
 285→const MEMORY_DB_REL = '.memory/memory.db';
 286→const MEMORY_SCHEMA_REL = '.founderOS/infrastructure/memory/schema/memory-store.sql';
 287→const REQUIRED_TABLES = 3; // memories, observations, adaptations
 288→
 289→export function initMemoryDb(projectRoot) {
 290→  const dbPath = path.join(projectRoot, MEMORY_DB_REL);
 291→  const schemaPath = path.join(projectRoot, MEMORY_SCHEMA_REL);
 292→
 293→  if (!fs.existsSync(schemaPath)) {
 294→    return { ready: false, error: 'schema-missing', tables: 0 };
 295→  }
 296→
 297→  try {
 298→    // Ensure .memory/ directory exists
 299→    const dir = path.dirname(dbPath);
 300→    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
 301→
 302→    const db = openDb(dbPath);
 303→    runSqlFile(db, schemaPath); // All CREATE IF NOT EXISTS — safe to re-run
 304→    const count = tableCount(db);
 305→    closeDb(db);
 306→
 307→    return { ready: count >= REQUIRED_TABLES, tables: count };
 308→  } catch (err) {
 309→    return { ready: false, error: err.message, tables: 0 };
 310→  }
 311→}
 312→```
