 760→function mergeHooksIntoSettingsJson(targetPath, registryPath) {
 761→  let existing = {};
 762→  if (fs.existsSync(targetPath)) {
 763→    existing = JSON.parse(fs.readFileSync(targetPath, 'utf8'));
 764→  }
 765→
 766→  const registry = JSON.parse(fs.readFileSync(registryPath, 'utf8'));
 767→
 768→  existing.hooks = existing.hooks || {};
 769→
 770→  let existingHooksDetected = false;
 771→  for (const [event, handlers] of Object.entries(registry.hooks)) {
 772→    existing.hooks[event] = existing.hooks[event] || [];
 773→    if (existing.hooks[event].length > 0) existingHooksDetected = true;
 774→    for (const handler of handlers) {
 775→      const isDuplicate = existing.hooks[event].some(h => h.command === handler.command);
 776→      if (!isDuplicate) {
 777→        existing.hooks[event].push(handler);
 778→      }
 779→    }
 780→  }
 781→
 782→  fs.writeFileSync(targetPath, JSON.stringify(existing, null, 2) + '\n');
 783→  return { existingHooksDetected };
 784→}
 785→
 786→function removeHooksFromSettingsJson(targetPath) {
 787→  if (!fs.existsSync(targetPath)) return;
 788→
