 1→// lib/settings-json.js
 2→// settings.json merge logic — append founderOS permissions without overwriting user settings
 3→'use strict';
 4→
 5→const fs = require('fs');
 6→
 7→const FOUNDER_OS_PERMISSIONS = [
 8→  'Bash(npx founder-os*)',
 9→  'Bash(node .founderOS/scripts/*)',
10→];
11→
12→function mergeSettingsJson(targetPath) {
13→  let existing = {};
14→  if (fs.existsSync(targetPath)) {
15→    existing = JSON.parse(fs.readFileSync(targetPath, 'utf8'));
16→  }
17→
18→  // Ensure permissions.allow array exists
19→  if (!existing.permissions) existing.permissions = {};
20→  if (!Array.isArray(existing.permissions.allow)) existing.permissions.allow = [];
21→
22→  // Append founderOS permissions if not present
23→  for (const perm of FOUNDER_OS_PERMISSIONS) {
24→    if (!existing.permissions.allow.includes(perm)) {
25→      existing.permissions.allow.push(perm);
26→    }
27→  }
28→
29→  fs.writeFileSync(targetPath, JSON.stringify(existing, null, 2) + '\n');
30→  return existing;
31→}
32→
33→function removeFromSettingsJson(targetPath) {
34→  if (!fs.existsSync(targetPath)) return;
35→
36→  const existing = JSON.parse(fs.readFileSync(targetPath, 'utf8'));
37→  if (existing.permissions?.allow) {
38→    existing.permissions.allow = existing.permissions.allow.filter(
39→      (p) => !FOUNDER_OS_PERMISSIONS.includes(p)
40→    );
41→    if (existing.permissions.allow.length === 0) delete existing.permissions.allow;
42→    if (Object.keys(existing.permissions).length === 0) delete existing.permissions;
43→  }
44→
45→  // If settings is now empty, delete the file
46→  if (Object.keys(existing).length === 0) {
47→    fs.unlinkSync(targetPath);
48→    return;
49→  }
50→
51→  fs.writeFileSync(targetPath, JSON.stringify(existing, null, 2) + '\n');
52→}
53→
54→module.exports = { mergeSettingsJson, removeFromSettingsJson, FOUNDER_OS_PERMISSIONS };
